function sumArray(numbers) {
    let total = 0;
    for (let i = 0; i < numbers.length; i++) {
        total += numbers[i];
    }
    return total;
}

const nums = [1, 2, 3, 4, 5];
console.log(sumArray(nums));

const users = [
    { name: "Alice", age: 25, active: true },
